MavAutopilot.fromValue = function(value) {
  for (const key of Object.keys(MavAutopilot)) {
    if (key === 'fromValue') continue;
    if (MavAutopilot[key] === value) return MavAutopilot[key];
  }
  return MavAutopilot[Object.keys(MavAutopilot).find((k) => k !== 'fromValue')];
};

