// These flags encode the MAV mode.
// MAV_MODE_FLAG
export const MavModeFlag = {
  // 0b10000000 MAV safety set to armed. Motors are enabled / running / can start. Ready to fly. Additional note: this flag is to be ignore when sent in the command MAV_CMD_DO_SET_MODE and MAV_CMD_COMPONENT_ARM_DISARM shall be used instead. The flag can still be used to report the armed state.
  // MAV_MODE_FLAG_SAFETY_ARMED
  MAV_MODE_FLAG_SAFETY_ARMED: 128,
  // 0b01000000 remote control input is enabled.
  // MAV_MODE_FLAG_MANUAL_INPUT_ENABLED
  MAV_MODE_FLAG_MANUAL_INPUT_ENABLED: 64,
  // 0b00100000 hardware in the loop simulation. All motors / actuators are blocked, but internal software is full operational.
  // MAV_MODE_FLAG_HIL_ENABLED
  MAV_MODE_FLAG_HIL_ENABLED: 32,
  // 0b00010000 system stabilizes electronically its attitude (and optionally position). It needs however further control inputs to move around.
  // MAV_MODE_FLAG_STABILIZE_ENABLED
  MAV_MODE_FLAG_STABILIZE_ENABLED: 16,
  // 0b00001000 guided mode enabled, system flies waypoints / mission items.
  // MAV_MODE_FLAG_GUIDED_ENABLED
  MAV_MODE_FLAG_GUIDED_ENABLED: 8,
  // 0b00000100 autonomous mode enabled, system finds its own goal positions. Guided flag can be set or not, depends on the actual implementation.
  // MAV_MODE_FLAG_AUTO_ENABLED
  MAV_MODE_FLAG_AUTO_ENABLED: 4,
  // 0b00000010 system has a test mode enabled. This flag is intended for temporary system tests and should not be used for stable implementations.
  // MAV_MODE_FLAG_TEST_ENABLED
  MAV_MODE_FLAG_TEST_ENABLED: 2,
  // 0b00000001 Reserved for future use.
  // MAV_MODE_FLAG_CUSTOM_MODE_ENABLED
  MAV_MODE_FLAG_CUSTOM_MODE_ENABLED: 1
};

MavModeFlag.fromValue = function(value) {
  // Exact match first
  for (const key of Object.keys(MavModeFlag)) {
    if (key === 'fromValue') continue;
    if (MavModeFlag[key] === value) return MavModeFlag[key];
  }
  // For bitmasks, find the highest priority set bit
  const sorted = Object.keys(MavModeFlag).filter((k) => k !== 'fromValue' && MavModeFlag[k] > 0).sort((a, b) => MavModeFlag[b] - MavModeFlag[a]);
  for (const key of sorted) {
    if ((value & MavModeFlag[key]) !== 0) return MavModeFlag[key];
  }
  const zero = Object.keys(MavModeFlag).find((k) => k !== 'fromValue' && MavModeFlag[k] === 0);
  return zero !== undefined ? MavModeFlag[zero] : MavModeFlag[Object.keys(MavModeFlag).find((k) => k !== 'fromValue')];
};

// These values encode the bit positions of the decode position. These values can be used to read the value of a flag bit by combining the base_mode variable with AND with the flag position value. The result will be either 0 or 1, depending on if the flag is set or not.
// MAV_MODE_FLAG_DECODE_POSITION
export const MavModeFlagDecodePosition = {
  // First bit:  10000000
  // MAV_MODE_FLAG_DECODE_POSITION_SAFETY
  MAV_MODE_FLAG_DECODE_POSITION_SAFETY: 128,
  // Second bit: 01000000
  // MAV_MODE_FLAG_DECODE_POSITION_MANUAL
  MAV_MODE_FLAG_DECODE_POSITION_MANUAL: 64,
  // Third bit:  00100000
  // MAV_MODE_FLAG_DECODE_POSITION_HIL
  MAV_MODE_FLAG_DECODE_POSITION_HIL: 32,
  // Fourth bit: 00010000
  // MAV_MODE_FLAG_DECODE_POSITION_STABILIZE
  MAV_MODE_FLAG_DECODE_POSITION_STABILIZE: 16,
  // Fifth bit:  00001000
  // MAV_MODE_FLAG_DECODE_POSITION_GUIDED
  MAV_MODE_FLAG_DECODE_POSITION_GUIDED: 8,
  // Sixth bit:   00000100
  // MAV_MODE_FLAG_DECODE_POSITION_AUTO
  MAV_MODE_FLAG_DECODE_POSITION_AUTO: 4,
  // Seventh bit: 00000010
  // MAV_MODE_FLAG_DECODE_POSITION_TEST
  MAV_MODE_FLAG_DECODE_POSITION_TEST: 2,
  // Eighth bit: 00000001
  // MAV_MODE_FLAG_DECODE_POSITION_CUSTOM_MODE
  MAV_MODE_FLAG_DECODE_POSITION_CUSTOM_MODE: 1
};

MavModeFlagDecodePosition.fromValue = function(value) {
  // Exact match first
  for (const key of Object.keys(MavModeFlagDecodePosition)) {
    if (key === 'fromValue') continue;
    if (MavModeFlagDecodePosition[key] === value) return MavModeFlagDecodePosition[key];
  }
  // For bitmasks, find the highest priority set bit
  const sorted = Object.keys(MavModeFlagDecodePosition).filter((k) => k !== 'fromValue' && MavModeFlagDecodePosition[k] > 0).sort((a, b) => MavModeFlagDecodePosition[b] - MavModeFlagDecodePosition[a]);
  for (const key of sorted) {
    if ((value & MavModeFlagDecodePosition[key]) !== 0) return MavModeFlagDecodePosition[key];
  }
  const zero = Object.keys(MavModeFlagDecodePosition).find((k) => k !== 'fromValue' && MavModeFlagDecodePosition[k] === 0);
  return zero !== undefined ? MavModeFlagDecodePosition[zero] : MavModeFlagDecodePosition[Object.keys(MavModeFlagDecodePosition).find((k) => k !== 'fromValue')];
};

// MAV_STATE
export const MavState = {
  // Uninitialized system, state is unknown.
  // MAV_STATE_UNINIT
  MAV_STATE_UNINIT: 0,
  // System is booting up.
  // MAV_STATE_BOOT
  MAV_STATE_BOOT: 1,
  // System is calibrating and not flight-ready.
  // MAV_STATE_CALIBRATING
  MAV_STATE_CALIBRATING: 2,
  // System is grounded and on standby. It can be launched any time.
  // MAV_STATE_STANDBY
  MAV_STATE_STANDBY: 3,
  // System is active and might be already airborne. Motors are engaged.
  // MAV_STATE_ACTIVE
  MAV_STATE_ACTIVE: 4,
  // System is in a non-normal flight mode. It can however still navigate.
  // MAV_STATE_CRITICAL
  MAV_STATE_CRITICAL: 5,
  // System is in a non-normal flight mode. It lost control over parts or over the whole airframe. It is in mayday and going down.
  // MAV_STATE_EMERGENCY
  MAV_STATE_EMERGENCY: 6,
  // System just initialized its power-down sequence, will shut down now.
  // MAV_STATE_POWEROFF
  MAV_STATE_POWEROFF: 7,
  // System is terminating itself.
  // MAV_STATE_FLIGHT_TERMINATION
  MAV_STATE_FLIGHT_TERMINATION: 8
};

MavState.fromValue = function(value) {
  for (const key of Object.keys(MavState)) {
    if (key === 'fromValue') continue;
    if (MavState[key] === value) return MavState[key];
  }
  return MavState[Object.keys(MavState).find((k) => k !== 'fromValue')];
};

