MavComponent.fromValue = function(value) {
  for (const key of Object.keys(MavComponent)) {
    if (key === 'fromValue') continue;
    if (MavComponent[key] === value) return MavComponent[key];
  }
  return MavComponent[Object.keys(MavComponent).find((k) => k !== 'fromValue')];
};

