// Flags to report failure cases over the high latency telemtry.
// HL_FAILURE_FLAG
export const HlFailureFlag = {
  // GPS failure.
  // HL_FAILURE_FLAG_GPS
  HL_FAILURE_FLAG_GPS: 1,
  // Differential pressure sensor failure.
  // HL_FAILURE_FLAG_DIFFERENTIAL_PRESSURE
  HL_FAILURE_FLAG_DIFFERENTIAL_PRESSURE: 2,
  // Absolute pressure sensor failure.
  // HL_FAILURE_FLAG_ABSOLUTE_PRESSURE
  HL_FAILURE_FLAG_ABSOLUTE_PRESSURE: 4,
  // Accelerometer sensor failure.
  // HL_FAILURE_FLAG_3D_ACCEL
  HL_FAILURE_FLAG_3D_ACCEL: 8,
  // Gyroscope sensor failure.
  // HL_FAILURE_FLAG_3D_GYRO
  HL_FAILURE_FLAG_3D_GYRO: 16,
  // Magnetometer sensor failure.
  // HL_FAILURE_FLAG_3D_MAG
  HL_FAILURE_FLAG_3D_MAG: 32,
  // Terrain subsystem failure.
  // HL_FAILURE_FLAG_TERRAIN
  HL_FAILURE_FLAG_TERRAIN: 64,
  // Battery failure/critical low battery.
  // HL_FAILURE_FLAG_BATTERY
  HL_FAILURE_FLAG_BATTERY: 128,
  // RC receiver failure/no rc connection.
  // HL_FAILURE_FLAG_RC_RECEIVER
  HL_FAILURE_FLAG_RC_RECEIVER: 256,
  // Offboard link failure.
  // HL_FAILURE_FLAG_OFFBOARD_LINK
  HL_FAILURE_FLAG_OFFBOARD_LINK: 512,
  // Engine failure.
  // HL_FAILURE_FLAG_ENGINE
  HL_FAILURE_FLAG_ENGINE: 1024,
  // Geofence violation.
  // HL_FAILURE_FLAG_GEOFENCE
  HL_FAILURE_FLAG_GEOFENCE: 2048,
  // Estimator failure, for example measurement rejection or large variances.
  // HL_FAILURE_FLAG_ESTIMATOR
  HL_FAILURE_FLAG_ESTIMATOR: 4096,
  // Mission failure.
  // HL_FAILURE_FLAG_MISSION
  HL_FAILURE_FLAG_MISSION: 8192
};

HlFailureFlag.fromValue = function(value) {
  // Exact match first
  for (const key of Object.keys(HlFailureFlag)) {
    if (key === 'fromValue') continue;
    if (HlFailureFlag[key] === value) return HlFailureFlag[key];
  }
  // For bitmasks, find the highest priority set bit
  const sorted = Object.keys(HlFailureFlag).filter((k) => k !== 'fromValue' && HlFailureFlag[k] > 0).sort((a, b) => HlFailureFlag[b] - HlFailureFlag[a]);
  for (const key of sorted) {
    if ((value & HlFailureFlag[key]) !== 0) return HlFailureFlag[key];
  }
  const zero = Object.keys(HlFailureFlag).find((k) => k !== 'fromValue' && HlFailureFlag[k] === 0);
  return zero !== undefined ? HlFailureFlag[zero] : HlFailureFlag[Object.keys(HlFailureFlag).find((k) => k !== 'fromValue')];
};

// Actions that may be specified in MAV_CMD_OVERRIDE_GOTO to override mission execution.
// MAV_GOTO
export const MavGoto = {
  // Hold at the current position.
  // MAV_GOTO_DO_HOLD
  MAV_GOTO_DO_HOLD: 0,
  // Continue with the next item in mission execution.
  // MAV_GOTO_DO_CONTINUE
  MAV_GOTO_DO_CONTINUE: 1,
  // Hold at the current position of the system
  // MAV_GOTO_HOLD_AT_CURRENT_POSITION
  MAV_GOTO_HOLD_AT_CURRENT_POSITION: 2,
  // Hold at the position specified in the parameters of the DO_HOLD action
  // MAV_GOTO_HOLD_AT_SPECIFIED_POSITION
  MAV_GOTO_HOLD_AT_SPECIFIED_POSITION: 3
};

MavGoto.fromValue = function(value) {
  for (const key of Object.keys(MavGoto)) {
    if (key === 'fromValue') continue;
    if (MavGoto[key] === value) return MavGoto[key];
  }
  return MavGoto[Object.keys(MavGoto).find((k) => k !== 'fromValue')];
};

