// These flags are used in the AIS_VESSEL.fields bitmask to indicate validity of data in the other message fields. When set, the data is valid.
// AIS_FLAGS
export const AisFlags = {
  // 1 = Position accuracy less than 10m, 0 = position accuracy greater than 10m.
  // AIS_FLAGS_POSITION_ACCURACY
  AIS_FLAGS_POSITION_ACCURACY: 1,
  // AIS_FLAGS_VALID_COG
  AIS_FLAGS_VALID_COG: 2,
  // AIS_FLAGS_VALID_VELOCITY
  AIS_FLAGS_VALID_VELOCITY: 4,
  // 1 = Velocity over 52.5765m/s (102.2 knots)
  // AIS_FLAGS_HIGH_VELOCITY
  AIS_FLAGS_HIGH_VELOCITY: 8,
  // AIS_FLAGS_VALID_TURN_RATE
  AIS_FLAGS_VALID_TURN_RATE: 16,
  // Only the sign of the returned turn rate value is valid, either greater than 5deg/30s or less than -5deg/30s
  // AIS_FLAGS_TURN_RATE_SIGN_ONLY
  AIS_FLAGS_TURN_RATE_SIGN_ONLY: 32,
  // AIS_FLAGS_VALID_DIMENSIONS
  AIS_FLAGS_VALID_DIMENSIONS: 64,
  // Distance to bow is larger than 511m
  // AIS_FLAGS_LARGE_BOW_DIMENSION
  AIS_FLAGS_LARGE_BOW_DIMENSION: 128,
  // Distance to stern is larger than 511m
  // AIS_FLAGS_LARGE_STERN_DIMENSION
  AIS_FLAGS_LARGE_STERN_DIMENSION: 256,
  // Distance to port side is larger than 63m
  // AIS_FLAGS_LARGE_PORT_DIMENSION
  AIS_FLAGS_LARGE_PORT_DIMENSION: 512,
  // Distance to starboard side is larger than 63m
  // AIS_FLAGS_LARGE_STARBOARD_DIMENSION
  AIS_FLAGS_LARGE_STARBOARD_DIMENSION: 1024,
  // AIS_FLAGS_VALID_CALLSIGN
  AIS_FLAGS_VALID_CALLSIGN: 2048,
  // AIS_FLAGS_VALID_NAME
  AIS_FLAGS_VALID_NAME: 4096
};

AisFlags.fromValue = function(value) {
  // Exact match first
  for (const key of Object.keys(AisFlags)) {
    if (key === 'fromValue') continue;
    if (AisFlags[key] === value) return AisFlags[key];
  }
  // For bitmasks, find the highest priority set bit
  const sorted = Object.keys(AisFlags).filter((k) => k !== 'fromValue' && AisFlags[k] > 0).sort((a, b) => AisFlags[b] - AisFlags[a]);
  for (const key of sorted) {
    if ((value & AisFlags[key]) !== 0) return AisFlags[key];
  }
  const zero = Object.keys(AisFlags).find((k) => k !== 'fromValue' && AisFlags[k] === 0);
  return zero !== undefined ? AisFlags[zero] : AisFlags[Object.keys(AisFlags).find((k) => k !== 'fromValue')];
};

