// GOPRO_HEARTBEAT_FLAGS
export const GoproHeartbeatFlags = {
  // GoPro is currently recording.
  // GOPRO_FLAG_RECORDING
  GOPRO_FLAG_RECORDING: 1
};

GoproHeartbeatFlags.fromValue = function(value) {
  // Exact match first
  for (const key of Object.keys(GoproHeartbeatFlags)) {
    if (key === 'fromValue') continue;
    if (GoproHeartbeatFlags[key] === value) return GoproHeartbeatFlags[key];
  }
  // For bitmasks, find the highest priority set bit
  const sorted = Object.keys(GoproHeartbeatFlags).filter((k) => k !== 'fromValue' && GoproHeartbeatFlags[k] > 0).sort((a, b) => GoproHeartbeatFlags[b] - GoproHeartbeatFlags[a]);
  for (const key of sorted) {
    if ((value & GoproHeartbeatFlags[key]) !== 0) return GoproHeartbeatFlags[key];
  }
  const zero = Object.keys(GoproHeartbeatFlags).find((k) => k !== 'fromValue' && GoproHeartbeatFlags[k] === 0);
  return zero !== undefined ? GoproHeartbeatFlags[zero] : GoproHeartbeatFlags[Object.keys(GoproHeartbeatFlags).find((k) => k !== 'fromValue')];
};

