// Flags in EKF_STATUS message.
// EKF_STATUS_FLAGS
export const EkfStatusFlags = {
  // Set if EKF's attitude estimate is good.
  // EKF_ATTITUDE
  EKF_ATTITUDE: 1,
  // Set if EKF's horizontal velocity estimate is good.
  // EKF_VELOCITY_HORIZ
  EKF_VELOCITY_HORIZ: 2,
  // Set if EKF's vertical velocity estimate is good.
  // EKF_VELOCITY_VERT
  EKF_VELOCITY_VERT: 4,
  // Set if EKF's horizontal position (relative) estimate is good.
  // EKF_POS_HORIZ_REL
  EKF_POS_HORIZ_REL: 8,
  // Set if EKF's horizontal position (absolute) estimate is good.
  // EKF_POS_HORIZ_ABS
  EKF_POS_HORIZ_ABS: 16,
  // Set if EKF's vertical position (absolute) estimate is good.
  // EKF_POS_VERT_ABS
  EKF_POS_VERT_ABS: 32,
  // Set if EKF's vertical position (above ground) estimate is good.
  // EKF_POS_VERT_AGL
  EKF_POS_VERT_AGL: 64,
  // EKF is in constant position mode and does not know it's absolute or relative position.
  // EKF_CONST_POS_MODE
  EKF_CONST_POS_MODE: 128,
  // Set if EKF's predicted horizontal position (relative) estimate is good.
  // EKF_PRED_POS_HORIZ_REL
  EKF_PRED_POS_HORIZ_REL: 256,
  // Set if EKF's predicted horizontal position (absolute) estimate is good.
  // EKF_PRED_POS_HORIZ_ABS
  EKF_PRED_POS_HORIZ_ABS: 512,
  // Set if EKF has never been healthy.
  // EKF_UNINITIALIZED
  EKF_UNINITIALIZED: 1024
};

EkfStatusFlags.fromValue = function(value) {
  // Exact match first
  for (const key of Object.keys(EkfStatusFlags)) {
    if (key === 'fromValue') continue;
    if (EkfStatusFlags[key] === value) return EkfStatusFlags[key];
  }
  // For bitmasks, find the highest priority set bit
  const sorted = Object.keys(EkfStatusFlags).filter((k) => k !== 'fromValue' && EkfStatusFlags[k] > 0).sort((a, b) => EkfStatusFlags[b] - EkfStatusFlags[a]);
  for (const key of sorted) {
    if ((value & EkfStatusFlags[key]) !== 0) return EkfStatusFlags[key];
  }
  const zero = Object.keys(EkfStatusFlags).find((k) => k !== 'fromValue' && EkfStatusFlags[k] === 0);
  return zero !== undefined ? EkfStatusFlags[zero] : EkfStatusFlags[Object.keys(EkfStatusFlags).find((k) => k !== 'fromValue')];
};

