// Modify the filter of what CAN messages to forward over the mavlink. This can be used to make CAN forwarding work well on low bandwith links. The filtering is applied on bits 8 to 24 of the CAN id (2nd and 3rd bytes) which corresponds to the DroneCAN message ID for DroneCAN. Filters with more than 16 IDs can be constructed by sending multiple CAN_FILTER_MODIFY messages.
// CAN_FILTER_MODIFY
export class CanFilterModify extends MavlinkMessage {
  static MSG_ID = 388;
  static CRC_EXTRA = 8;
  static MAVLINK_ENCODED_LENGTH = 37;

  get mavlinkMessageId() {
    return CanFilterModify.MSG_ID;
  }

  get mavlinkCrcExtra() {
    return CanFilterModify.CRC_EXTRA;
  }

  constructor(ids, target_system, target_component, bus, operation, num_ids) {
    super();
    this.ids = ids;
    this.target_system = target_system;
    this.target_component = target_component;
    this.bus = bus;
    this.operation = operation;
    this.num_ids = num_ids;
  }

  copyWith(overrides = {}) {
    return new CanFilterModify(
      overrides.ids ?? this.ids,
      overrides.target_system ?? this.target_system,
      overrides.target_component ?? this.target_component,
      overrides.bus ?? this.bus,
      overrides.operation ?? this.operation,
      overrides.num_ids ?? this.num_ids
    );
  }

  static parse(wire) {
    if (wire.length < this.MAVLINK_ENCODED_LENGTH) {
      const padded = new Uint8Array(this.MAVLINK_ENCODED_LENGTH);
      padded.set(wire);
      wire = padded;
    }
    const ids = MavlinkMessage._getUint16List(wire, 0, 16);
    const target_system = MavlinkMessage._getUint8(wire, 32);
    const target_component = MavlinkMessage._getUint8(wire, 33);
    const bus = MavlinkMessage._getUint8(wire, 34);
    const operation_raw = MavlinkMessage._getUint8(wire, 35);
    const operation = CanFilterOp.fromValue(operation_raw);
    const num_ids = MavlinkMessage._getUint8(wire, 36);

    return new CanFilterModify(
      ids,
      target_system,
      target_component,
      bus,
      operation,
      num_ids
    );
  }

  serialize() {
    const buffer = new Uint8Array(CanFilterModify.MAVLINK_ENCODED_LENGTH);
    MavlinkMessage._setUint16List(buffer, 0, this.ids);
    MavlinkMessage._setUint8(buffer, 32, this.target_system);
    MavlinkMessage._setUint8(buffer, 33, this.target_component);
    MavlinkMessage._setUint8(buffer, 34, this.bus);
    MavlinkMessage._setUint8(buffer, 35, this.operation);
    MavlinkMessage._setUint8(buffer, 36, this.num_ids);
    return buffer;
  }
}

