    const lng = MavlinkMessage._getInt32(wire, 4);
    const alt = MavlinkMessage._getInt16(wire, 8);
    const break_alt = MavlinkMessage._getInt16(wire, 10);
    const land_dir = MavlinkMessage._getUint16(wire, 12);
    const target_system = MavlinkMessage._getUint8(wire, 14);
    const target_component = MavlinkMessage._getUint8(wire, 15);
    const idx = MavlinkMessage._getUint8(wire, 16);
    const count = MavlinkMessage._getUint8(wire, 17);
