export class AutopilotVersionRequest extends MavlinkMessage {
  static MSG_ID = 183;
  static CRC_EXTRA = 85;
  static MAVLINK_ENCODED_LENGTH = 2;

  get mavlinkMessageId() {
    return AutopilotVersionRequest.MSG_ID;
  }

  get mavlinkCrcExtra() {
    return AutopilotVersionRequest.CRC_EXTRA;
  }

  constructor(target_system, target_component) {
    super();
    this.target_system = target_system;
    this.target_component = target_component;
  }

  copyWith(overrides = {}) {
    return new AutopilotVersionRequest(
      overrides.target_system ?? this.target_system,
      overrides.target_component ?? this.target_component
    );
  }

  static parse(wire) {
    if (wire.length < this.MAVLINK_ENCODED_LENGTH) {
      const padded = new Uint8Array(this.MAVLINK_ENCODED_LENGTH);
      padded.set(wire);
      wire = padded;
    }
    const target_system = MavlinkMessage._getUint8(wire, 0);
    const target_component = MavlinkMessage._getUint8(wire, 1);

    return new AutopilotVersionRequest(
      target_system,
      target_component
    );
  }

  serialize() {
    const buffer = new Uint8Array(AutopilotVersionRequest.MAVLINK_ENCODED_LENGTH);
    MavlinkMessage._setUint8(buffer, 0, this.target_system);
    MavlinkMessage._setUint8(buffer, 1, this.target_component);
    return buffer;
  }
}

// Send a block of log data to remote location.
// REMOTE_LOG_DATA_BLOCK
export class RemoteLogDataBlock extends MavlinkMessage {
  static MSG_ID = 184;
  static CRC_EXTRA = 159;
  static MAVLINK_ENCODED_LENGTH = 206;

  get mavlinkMessageId() {
    return RemoteLogDataBlock.MSG_ID;
  }

  get mavlinkCrcExtra() {
    return RemoteLogDataBlock.CRC_EXTRA;
  }

  constructor(seqno, target_system, target_component, data) {
    super();
    this.seqno = seqno;
    this.target_system = target_system;
    this.target_component = target_component;
    this.data = data;
  }

  copyWith(overrides = {}) {
    return new RemoteLogDataBlock(
      overrides.seqno ?? this.seqno,
      overrides.target_system ?? this.target_system,
      overrides.target_component ?? this.target_component,
      overrides.data ?? this.data
    );
  }

  static parse(wire) {
    if (wire.length < this.MAVLINK_ENCODED_LENGTH) {
      const padded = new Uint8Array(this.MAVLINK_ENCODED_LENGTH);
      padded.set(wire);
      wire = padded;
    }
    const seqno_raw = MavlinkMessage._getUint32(wire, 0);
    const seqno = MavRemoteLogDataBlockCommands.fromValue(seqno_raw);
    const target_system = MavlinkMessage._getUint8(wire, 4);
    const target_component = MavlinkMessage._getUint8(wire, 5);
    const data = MavlinkMessage._getUint8List(wire, 6, 200);

    return new RemoteLogDataBlock(
      seqno,
      target_system,
      target_component,
      data
    );
  }

  serialize() {
    const buffer = new Uint8Array(RemoteLogDataBlock.MAVLINK_ENCODED_LENGTH);
    MavlinkMessage._setUint32(buffer, 0, this.seqno);
    MavlinkMessage._setUint8(buffer, 4, this.target_system);
    MavlinkMessage._setUint8(buffer, 5, this.target_component);
    MavlinkMessage._setUint8List(buffer, 6, this.data);
    return buffer;
  }
}

