    const path_lon = MavlinkMessage._getInt32(wire, 12);
    const arc_entry_lat = MavlinkMessage._getInt32(wire, 16);
    const arc_entry_lon = MavlinkMessage._getInt32(wire, 20);
    const altitude = MavlinkMessage._getFloat32(wire, 24);
    const expected_travel_distance = MavlinkMessage._getFloat32(wire, 28);
    const cross_track_error = MavlinkMessage._getFloat32(wire, 32);
    const stage_raw = MavlinkMessage._getUint8(wire, 36);
