    MavlinkMessage._setInt32(buffer, 16, this.arc_entry_lat);
    MavlinkMessage._setInt32(buffer, 20, this.arc_entry_lon);
    MavlinkMessage._setFloat32(buffer, 24, this.altitude);
    MavlinkMessage._setFloat32(buffer, 28, this.expected_travel_distance);
    MavlinkMessage._setFloat32(buffer, 32, this.cross_track_error);
