// Send a secure command. Data should be signed with a private key corresponding with a public key known to the recipient. Signature should be over the concatenation of the sequence number (little-endian format), the operation (little-endian format) the data and the session key. For SECURE_COMMAND_GET_SESSION_KEY the session key should be zero length. The data array consists of the data followed by the signature. The sum of the data_length and the sig_length cannot be more than 220. The format of the data is command specific.
// SECURE_COMMAND
export class SecureCommand extends MavlinkMessage {
  static MSG_ID = 11004;
  static CRC_EXTRA = 11;
  static MAVLINK_ENCODED_LENGTH = 232;

  get mavlinkMessageId() {
    return SecureCommand.MSG_ID;
  }

  get mavlinkCrcExtra() {
    return SecureCommand.CRC_EXTRA;
  }

  constructor(sequence, operation, target_system, target_component, data_length, sig_length, data) {
    super();
    this.sequence = sequence;
    this.operation = operation;
    this.target_system = target_system;
    this.target_component = target_component;
    this.data_length = data_length;
    this.sig_length = sig_length;
    this.data = data;
  }

  copyWith(overrides = {}) {
    return new SecureCommand(
      overrides.sequence ?? this.sequence,
      overrides.operation ?? this.operation,
      overrides.target_system ?? this.target_system,
      overrides.target_component ?? this.target_component,
      overrides.data_length ?? this.data_length,
      overrides.sig_length ?? this.sig_length,
      overrides.data ?? this.data
    );
  }

  static parse(wire) {
    if (wire.length < this.MAVLINK_ENCODED_LENGTH) {
      const padded = new Uint8Array(this.MAVLINK_ENCODED_LENGTH);
      padded.set(wire);
      wire = padded;
    }
    const sequence = MavlinkMessage._getUint32(wire, 0);
    const operation_raw = MavlinkMessage._getUint32(wire, 4);
    const operation = SecureCommandOp.fromValue(operation_raw);
    const target_system = MavlinkMessage._getUint8(wire, 8);
    const target_component = MavlinkMessage._getUint8(wire, 9);
    const data_length = MavlinkMessage._getUint8(wire, 10);
    const sig_length = MavlinkMessage._getUint8(wire, 11);
    const data = MavlinkMessage._getUint8List(wire, 12, 220);

    return new SecureCommand(
      sequence,
      operation,
      target_system,
      target_component,
      data_length,
      sig_length,
      data
    );
  }

  serialize() {
    const buffer = new Uint8Array(SecureCommand.MAVLINK_ENCODED_LENGTH);
    MavlinkMessage._setUint32(buffer, 0, this.sequence);
    MavlinkMessage._setUint32(buffer, 4, this.operation);
    MavlinkMessage._setUint8(buffer, 8, this.target_system);
    MavlinkMessage._setUint8(buffer, 9, this.target_component);
    MavlinkMessage._setUint8(buffer, 10, this.data_length);
    MavlinkMessage._setUint8(buffer, 11, this.sig_length);
    MavlinkMessage._setUint8List(buffer, 12, this.data);
    return buffer;
  }
}

